import { asc, eq } from "drizzle-orm";
import type { AppDb } from "../client.js";
import {
  sessionConcepts,
  sessionEvaluations,
  sessionMessages,
  sessionQuestions,
  sessions,
} from "../schema.js";
import type { Session } from "@mock-interview/shared";
import type { SessionRepository } from "../../repositories/sessionRepository.js";
import {
  mapSessionAggregateToDomain,
  mapSessionToNormalizedRecord,
} from "../../repositories/mappers.js";

export class SQLiteSessionRepository implements SessionRepository {
  constructor(private readonly db: AppDb) {}

  list(): Session[] {
    const sessionRows = this.db.select().from(sessions).orderBy(asc(sessions.createdAt)).all();
    return sessionRows.map((row) => this.hydrate(row.id));
  }

  getById(id: string): Session | null {
    const row = this.db.select().from(sessions).where(eq(sessions.id, id)).get();
    return row ? this.hydrate(row.id) : null;
  }

  save(session: Session): void {
    const record = mapSessionToNormalizedRecord(session);

    this.db.transaction((tx) => {
      tx.insert(sessions).values(record.session).onConflictDoUpdate({
        target: sessions.id,
        set: {
          topic: record.session.topic,
          interviewType: record.session.interviewType,
          sessionKind: record.session.sessionKind,
          studyCategory: record.session.studyCategory,
          sourcePath: record.session.sourcePath,
          sourceType: record.session.sourceType,
          seeded: record.session.seeded,
          customContent: record.session.customContent,
          focusArea: record.session.focusArea,
          state: record.session.state,
          currentQuestionIndex: record.session.currentQuestionIndex,
          summary: record.session.summary,
          knowledgeSource: record.session.knowledgeSource,
          createdAt: record.session.createdAt,
          endedAt: record.session.endedAt,
        },
      }).run();

      tx.delete(sessionQuestions).where(eq(sessionQuestions.sessionId, session.id)).run();
      tx.delete(sessionMessages).where(eq(sessionMessages.sessionId, session.id)).run();
      tx.delete(sessionEvaluations).where(eq(sessionEvaluations.sessionId, session.id)).run();
      tx.delete(sessionConcepts).where(eq(sessionConcepts.sessionId, session.id)).run();

      if (record.questions.length) tx.insert(sessionQuestions).values(record.questions).run();
      if (record.messages.length) tx.insert(sessionMessages).values(record.messages).run();
      if (record.evaluations.length) tx.insert(sessionEvaluations).values(record.evaluations).run();
      if (record.concepts.length) tx.insert(sessionConcepts).values(record.concepts).run();
    });
  }

  saveMany(allSessions: Session[]): void {
    this.db.transaction((tx) => {
      for (const session of allSessions) {
        const record = mapSessionToNormalizedRecord(session);
        tx.insert(sessions).values(record.session).onConflictDoUpdate({
          target: sessions.id,
          set: {
            topic: record.session.topic,
            interviewType: record.session.interviewType,
            sessionKind: record.session.sessionKind,
            studyCategory: record.session.studyCategory,
            sourcePath: record.session.sourcePath,
            sourceType: record.session.sourceType,
            seeded: record.session.seeded,
            customContent: record.session.customContent,
            focusArea: record.session.focusArea,
            state: record.session.state,
            currentQuestionIndex: record.session.currentQuestionIndex,
            summary: record.session.summary,
            knowledgeSource: record.session.knowledgeSource,
            createdAt: record.session.createdAt,
            endedAt: record.session.endedAt,
          },
        }).run();

        tx.delete(sessionQuestions).where(eq(sessionQuestions.sessionId, session.id)).run();
        tx.delete(sessionMessages).where(eq(sessionMessages.sessionId, session.id)).run();
        tx.delete(sessionEvaluations).where(eq(sessionEvaluations.sessionId, session.id)).run();
        tx.delete(sessionConcepts).where(eq(sessionConcepts.sessionId, session.id)).run();

        if (record.questions.length) tx.insert(sessionQuestions).values(record.questions).run();
        if (record.messages.length) tx.insert(sessionMessages).values(record.messages).run();
        if (record.evaluations.length) tx.insert(sessionEvaluations).values(record.evaluations).run();
        if (record.concepts.length) tx.insert(sessionConcepts).values(record.concepts).run();
      }
    });
  }

  replaceAll(sessionsById: Record<string, Session>): void {
    this.db.transaction((tx) => {
      tx.delete(sessionQuestions).run();
      tx.delete(sessionMessages).run();
      tx.delete(sessionEvaluations).run();
      tx.delete(sessionConcepts).run();
      tx.delete(sessions).run();

      for (const session of Object.values(sessionsById)) {
        const record = mapSessionToNormalizedRecord(session);
        tx.insert(sessions).values(record.session).run();
        if (record.questions.length) tx.insert(sessionQuestions).values(record.questions).run();
        if (record.messages.length) tx.insert(sessionMessages).values(record.messages).run();
        if (record.evaluations.length) tx.insert(sessionEvaluations).values(record.evaluations).run();
        if (record.concepts.length) tx.insert(sessionConcepts).values(record.concepts).run();
      }
    });
  }

  deleteById(id: string): boolean {
    const result = this.db.transaction((tx) => {
      tx.delete(sessionQuestions).where(eq(sessionQuestions.sessionId, id)).run();
      tx.delete(sessionMessages).where(eq(sessionMessages.sessionId, id)).run();
      tx.delete(sessionEvaluations).where(eq(sessionEvaluations.sessionId, id)).run();
      tx.delete(sessionConcepts).where(eq(sessionConcepts.sessionId, id)).run();
      return tx.delete(sessions).where(eq(sessions.id, id)).run();
    });

    return result.changes > 0;
  }

  private hydrate(id: string): Session {
    const sessionRow = this.db.select().from(sessions).where(eq(sessions.id, id)).get();
    if (!sessionRow) throw new Error(`Session not found: ${id}`);

    return mapSessionAggregateToDomain({
      session: sessionRow,
      questions: this.db
        .select()
        .from(sessionQuestions)
        .where(eq(sessionQuestions.sessionId, id))
        .orderBy(asc(sessionQuestions.position))
        .all(),
      messages: this.db
        .select()
        .from(sessionMessages)
        .where(eq(sessionMessages.sessionId, id))
        .orderBy(asc(sessionMessages.position))
        .all(),
      evaluations: this.db
        .select()
        .from(sessionEvaluations)
        .where(eq(sessionEvaluations.sessionId, id))
        .orderBy(asc(sessionEvaluations.position))
        .all(),
      concepts: this.db
        .select()
        .from(sessionConcepts)
        .where(eq(sessionConcepts.sessionId, id))
        .all(),
    });
  }
}

import { asc, eq, lte } from "drizzle-orm";
import type { Skill, SkillSubSkill } from "@mock-interview/shared";
import type { AppDb } from "../client.js";
import { skills } from "../schema.js";
import type { SkillRepository } from "../../repositories/skillRepository.js";

export class SQLiteSkillRepository implements SkillRepository {
  constructor(private readonly db: AppDb) {}

  list(maxConfidence?: number): Skill[] {
    const rows = maxConfidence !== undefined
      ? this.db.select().from(skills).where(lte(skills.confidence, maxConfidence)).orderBy(asc(skills.confidence)).all()
      : this.db.select().from(skills).orderBy(asc(skills.confidence)).all();

    return rows.map((r) => this.hydrate(r));
  }

  findByName(name: string): Skill | null {
    const row = this.db.select().from(skills).where(eq(skills.name, name)).get();
    return row ? this.hydrate(row) : null;
  }

  insert(skill: Skill): void {
    this.db.insert(skills).values(this.dehydrate(skill)).run();
  }

  update(skill: Skill): void {
    this.db.update(skills)
      .set({
        confidence: skill.confidence,
        subSkills: JSON.stringify(skill.subSkills),
        relatedProblems: JSON.stringify(skill.relatedProblems),
        updatedAt: skill.updatedAt,
      })
      .where(eq(skills.id, skill.id))
      .run();
  }

  private hydrate(row: typeof skills.$inferSelect): Skill {
    return {
      id: row.id,
      name: row.name,
      confidence: row.confidence,
      subSkills: JSON.parse(row.subSkills) as SkillSubSkill[],
      relatedProblems: JSON.parse(row.relatedProblems) as string[],
      createdAt: row.createdAt,
      updatedAt: row.updatedAt,
    };
  }

  private dehydrate(skill: Skill) {
    return {
      id: skill.id,
      name: skill.name,
      confidence: skill.confidence,
      subSkills: JSON.stringify(skill.subSkills),
      relatedProblems: JSON.stringify(skill.relatedProblems),
      createdAt: skill.createdAt,
      updatedAt: skill.updatedAt,
    };
  }
}

import { asc, eq, lte, and } from "drizzle-orm";
import type { Exercise, ExercisePrerequisite } from "@mock-interview/shared";
import type { AppDb } from "../client.js";
import { exercises } from "../schema.js";
import type { ExerciseRepository } from "../../repositories/exerciseRepository.js";

export class SQLiteExerciseRepository implements ExerciseRepository {
  constructor(private readonly db: AppDb) {}

  list(topic?: string, maxDifficulty?: number, tags?: string[]): Exercise[] {
    let query = this.db.select().from(exercises).$dynamic();

    if (topic && maxDifficulty !== undefined) {
      query = query.where(and(eq(exercises.topic, topic), lte(exercises.difficulty, maxDifficulty)));
    } else if (topic) {
      query = query.where(eq(exercises.topic, topic));
    } else if (maxDifficulty !== undefined) {
      query = query.where(lte(exercises.difficulty, maxDifficulty));
    }

    const requestedTags = (tags ?? []).map((tag) => tag.trim()).filter(Boolean);

    return query
      .orderBy(asc(exercises.difficulty))
      .all()
      .map((r) => this.hydrate(r))
      .filter((exercise) => {
        if (requestedTags.length === 0) return true;
        return requestedTags.every((tag) => exercise.tags.includes(tag));
      });
  }

  findByName(name: string): Exercise | null {
    const row = this.db.select().from(exercises).where(eq(exercises.name, name)).get();
    return row ? this.hydrate(row) : null;
  }

  findBySlug(slug: string): Exercise | null {
    const row = this.db.select().from(exercises).where(eq(exercises.slug, slug)).get();
    return row ? this.hydrate(row) : null;
  }

  insert(exercise: Exercise): void {
    this.db.insert(exercises).values(this.dehydrate(exercise)).run();
  }

  private hydrate(row: typeof exercises.$inferSelect): Exercise {
    return {
      id: row.id,
      name: row.name,
      slug: row.slug,
      topic: row.topic,
      language: row.language,
      difficulty: row.difficulty as Exercise["difficulty"],
      description: row.description,
      scenario: row.scenario,
      problemMeaning: JSON.parse(row.problemMeaning) as string[],
      tags: JSON.parse(row.tags) as string[],
      prerequisites: JSON.parse(row.prerequisites) as ExercisePrerequisite[],
      filePath: row.filePath,
      createdAt: row.createdAt,
    };
  }

  private dehydrate(exercise: Exercise) {
    return {
      id: exercise.id,
      name: exercise.name,
      slug: exercise.slug,
      topic: exercise.topic,
      language: exercise.language,
      difficulty: exercise.difficulty,
      description: exercise.description,
      scenario: exercise.scenario,
      problemMeaning: JSON.stringify(exercise.problemMeaning),
      tags: JSON.stringify(exercise.tags),
      prerequisites: JSON.stringify(exercise.prerequisites),
      filePath: exercise.filePath,
      createdAt: exercise.createdAt,
    };
  }
}

import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { z } from "zod";
import type { Flashcard, FlashcardDifficulty } from "@mock-interview/shared";
import type { ToolDeps } from "./deps.js";

// ─────────────────────────────────────────────────────────────────────────────
// create_flashcard
//
// Creates a single flashcard from user-supplied content — decoupled from the
// interview flow. Also exports persistFlashcard() so end_interview can reuse
// the same insertion logic (SRP: one place that knows how to save a card).
// ─────────────────────────────────────────────────────────────────────────────

/** Idempotent single-card save — skips if the id already exists. */
export function persistFlashcard(deps: ToolDeps, card: Flashcard): boolean {
  const existing = deps.loadFlashcards();
  if (existing.some((c) => c.id === card.id)) return false;
  deps.saveFlashcard(card);
  return true;
}

export function registerCreateFlashcardTool(server: McpServer, deps: ToolDeps) {
  server.registerTool(
    "create_flashcard",
    {
      description: "Create a flashcard directly from supplied front/back content. " +
      "Useful for capturing insights, concepts, or mistakes outside of an interview session. " +
      "Cards are immediately due for review and follow the same SM-2 schedule as auto-generated cards.",
      inputSchema: {
        front: z.string().min(5)
          .describe("The question or concept prompt shown during review."),
        back: z.string().min(5)
          .describe("The answer, explanation, or key points revealed after the prompt. Markdown is supported."),
        topic: z.string().min(1)
          .describe("Topic label, e.g. 'Zero Matrix', 'JWT authentication'."),
        difficulty: z.enum(["easy", "medium", "hard"]).default("medium")
          .describe("How hard this card is: easy | medium | hard."),
        tags: z.array(z.string()).optional()
          .describe("Optional tags for filtering, e.g. ['arrays', 'in-place']."),
      },
    },
    async ({ front, back, topic, difficulty, tags }) => {
      const now = new Date().toISOString();
      const id  = `fc-manual-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`;

      const card: Flashcard = {
        id,
        front,
        back,
        topic,
        difficulty: difficulty as FlashcardDifficulty,
        tags: tags ?? topic.toLowerCase().replace(/[^a-z0-9 ]/g, "").split(/\s+/).filter(Boolean),
        // No source — manually created cards are not tied to a session
        createdAt:   now,
        dueDate:     now,   // due immediately
        interval:    1,
        easeFactor:  2.5,
        repetitions: 0,
      };

      const created = persistFlashcard(deps, card);

      return {
        content: [{
          type: "text" as const,
          text: JSON.stringify({
            created,
            cardId:     card.id,
            topic:      card.topic,
            difficulty: card.difficulty,
            dueDate:    card.dueDate,
            message:    created
              ? `Flashcard created — due immediately for first review.`
              : `Card '${id}' already exists — skipped.`,
          }, null, 2),
        }],
      };
    }
  );
}
